    ('celina-leao', 'PL', '2896', 2022, 'Altera o art. 93 da Lei nº 13.303, de 30 de junho de 2016, para dispor sobre gastos com publicidade da empresa pública, da sociedade de economia mista e de suas subsidiárias. NOVA EMENTA: Altera a Lei nº 13.303, de 30 de junho de 2016, para dispor sobre as vedações a serem observadas na indicação de pessoas para o conselho de administração e para a diretoria das estatais e sobre os gastos com publicidade e patrocínio da empresa pública e da sociedade de economia mista e suas subsidiárias, e a Lei nº 9.986, de 18 de julho de 2000, para dispor sobre as vedações a serem observadas na indicação de pessoas para o conselho diretor ou a diretoria colegiada das agências reguladoras.', 'Camara', '2340532', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=2219764', 'celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"celina-leao-camara-completo-lote-b-20260511","coverage_id":"celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511","previous_coverage_id":"celina-leao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"celina-leao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":204380,"proposicao_id_api":"2340532","data_apresentacao":"2022