    ('celina-leao', 'PL', '1883', 2021, 'Dispõe sobre mecanismos de facilitação do crédito a microempresas e empresas de pequeno porte controladas e dirigidas por mulheres e a microempreendedoras individuais e altera a Lei nº 13.483, de 21 de setembro de 2017, e a Lei nº 13.999, de 18 de maio de 2020. NOVA EMENTA: Institui o Programa Crédito da Mulher no âmbito das instituições financeiras oficiais federais e mecanismos de facilitação do crédito a microempreendedoras individuais e a microempresas e empresas de pequeno porte controladas e dirigidas por mulheres; e altera as Leis nºs 13.483, de 21 de setembro de 2017, 13.999, de 18 de maio de 2020, e 8.029, de 12 de abril de 1990.', 'Camara', '2283555', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=2014054', 'celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"celina-leao-camara-completo-lote-b-20260511","coverage_id":"celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511","previous_coverage_id":"celina-leao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"celina-leao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":204380,"proposicao_id_api":"2283555","data_apresentacao":"2021-05-19T14:54","ordem_assinatura":1,"p