    ('celina-leao', 'PL', '302', 2021, 'Altera a Lei nº 9.394, de 20 de dezembro de 1996, que estabelece as diretrizes e bases da educação nacional, e altera a Lei nº 12.711, de 29 de agosto de 2012, que dispõe sobre o ingresso nas universidades federais e nas instituições federais de ensino técnico de nível médio e dá outras providências, para definir mecanismos que possibilitem a continuidade de estudos e a formação acadêmica de atletas de alto desempenho.', 'Camara', '2269527', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1961462', 'celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"celina-leao-camara-completo-lote-b-20260511","coverage_id":"celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511","previous_coverage_id":"celina-leao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"celina-leao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":204380,"proposicao_id_api":"2269527","data_apresentacao":"2021-02-08T14:10","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Celina Leão","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/204380","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/propo