    ('celina-leao', 'EMC', '20', 2019, 'Inclua-se no Projeto de Lei nº 1645, de 2019, que altera a Lei nº 6.880, de 9 de dezembro de 1980, que dispõe sobre o Estatuto dos Militares; a Lei nº 3.765, de 4 de maio de 1960, que dispõe sobre as pensões militares; a Lei nº 4.375, de 17 de agosto de 1964 - Lei do Serviço Militar; a Lei nº 5.821, de 10 de novembro de 1972, que dispõe sobre as promoções dos oficiais da ativa das Forças Armadas; e a Lei nº 12.705, de 8 de agosto de 2012, que dispõe sobre os requisitos para ingresso nos cursos de formação de militares de carreira do Exército, a seguinte emenda aditiva.', 'Camara', '2217309', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1797162', 'celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"celina-leao-camara-completo-lote-b-20260511","coverage_id":"celina-leao-camara-completo-autoria-principal-tipos-verificados-2019-2022-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2019_2022_cutoff_20260511","previous_coverage_id":"celina-leao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"celina-leao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":204380,"proposicao_id_api":"2217309","data_apresentacao":"2019-08-27T16:03","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Celina Leão","autor_tipo":"