    ('decio-lima', 'REQ', '8408', 2013, 'Requeiro, nos termos dos arts. 24, 32, 41 e 53 do Regimento Interno da Câmara dos Deputados, que o Projeto de Lei Complementar (PLP) do Senado nº 302/2013, que dispõe sobre o contrato de trabalho doméstico e dá outras providências, tramite pela Comissão Constituição e Justiça e de Cidadania da Câmara dos Deputados, da qual sou presidente, e que é competente para se manifestar a respeito da matéria, de acordo com o art. 32, inciso IV, do Regimento Interno.', 'Camara', '588662', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1119200', 'decio-lima-camara-completo-autoria-principal-tipos-verificados-2007-2018-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2007_2018_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"decio-lima-camara-completo-lote-b-20260511","coverage_id":"decio-lima-camara-completo-autoria-principal-tipos-verificados-2007-2018-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2007_2018_cutoff_20260511","previous_coverage_id":"decio-lima-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"decio-lima-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":141413,"proposicao_id_api":"588662","data_apresentacao":"2013-08-21T18:29","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Décio Lima","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/141413","detalhe_endpoint":"https://dadosaber