    ('fabio-mitidieri', 'REQ', '1552', 2015, 'Requer a Inclusão na Ordem do Dia da Proposta de Emenda à Constituição nº 443 de 2009, que dispõe sobre subsídio do grau ou nível máximo das carreiras da Advocacia-Geral da União, das Procuradorias dos Estados e do Distrito Federal corresponderá a noventa inteiros e vinte e cinco centésimos por cento do subsídio mensal, fixado para os Ministros do Supremo Tribunal Federal, e os subsídios dos demais integrantes das respectivas categorias da estrutura da advocacia pública serão fixados em lei e escalonados, não podendo a diferença entre um e outro ser superior a dez por centro ou inferior a cinco por cento, nem exceder a noventa inteiros e vinte e cinco centésimos por cento do subsídio mensal fixado para os Ministros do Supremo Tribunal Federal, obedecido, em qualquer caso, o disposto nos artigos 37, XI, e 39, § 4º.', 'Camara', '1215699', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1325396', 'fabio-mitidieri-camara-completo-autoria-principal-tipos-verificados-2015-2022-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2022_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"fabio-mitidieri-camara-completo-lote-b-20260511","coverage_id":"fabio-mitidieri-camara-completo-autoria-principal-tipos-verificados-2015-2022-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2022_cutoff_20260511","previous_coverage_id":"fabio-mitidieri-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"fabio-mitidieri-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipo