    ('gilberto-kassab', 'EMC', '159', 2004, 'Dê-se ao caput e aos §§ 1º a 5º do art. 5º a seguinte redação: "Art. 5º Fica criada a Gratificação de Incremento à Arrecadação e Fiscalização do Trabalho - GIAFT, devida aos ocupantes dos cargos efetivos da Carreira de Auditoria-Fiscal do Trabalho, de que trata a Lei nº 10.593, de 2002, em função do cumprimento de metas de fiscalização do trabalho e de arrecadação, no percentual de até quarenta e cinco por cento, incidente sobre o maior vencimento básico do cargo.', 'Camara', '255140', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=222014', 'gilberto-kassab-camara-completo-autoria-principal-tipos-verificados-1999-2004-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_1999_2004_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"gilberto-kassab-camara-completo-lote-b-20260511","coverage_id":"gilberto-kassab-camara-completo-autoria-principal-tipos-verificados-1999-2004-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_1999_2004_cutoff_20260511","previous_coverage_id":"gilberto-kassab-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"gilberto-kassab-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":74778,"proposicao_id_api":"255140","data_apresentacao":"2004-05-25T20:06","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Gilberto Kassab","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/7477