    ('gilberto-kassab', 'EMC', '158', 2004, 'Dê-se ao inciso II do art. 3º, ao caput do art. 4º, ao art. 6º (renumerado como 5º), ao art. 10 (renumerado como 6º), ao art. 11 (renumerado como 7º), ao caput do art. 15 (renumerado como 10) , suprimindo-se os arts. 5º, 7º, 8º, 9º, 12 ,16 e 17, os parágrafos do art. 6º e os §§ 1º, 2º, 3º, 4º e 5º do art. 4º, bem como transformando-se em parágrafo único do art. 4º o § 6º do dispositivo, na forma igualmente a seguir discriminada:', 'Camara', '255138', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=222013', 'gilberto-kassab-camara-completo-autoria-principal-tipos-verificados-1999-2004-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_1999_2004_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"gilberto-kassab-camara-completo-lote-b-20260511","coverage_id":"gilberto-kassab-camara-completo-autoria-principal-tipos-verificados-1999-2004-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_1999_2004_cutoff_20260511","previous_coverage_id":"gilberto-kassab-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"gilberto-kassab-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":74778,"proposicao_id_api":"255138","data_apresentacao":"2004-05-25T20:04","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Gilberto Kassab","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/74778","detalhe_endpoint":"https://dados