    ('gilberto-kassab', 'EMC', '157', 2004, 'Inclua-se, onde couber, o seguinte artigo: "Art. ... A diária devida aos servidores integrantes das carreiras contempladas por esta lei corresponderão a 1/30 (um trinta avos) da parcela fixa da remuneração para eles prevista, considerando-se, para esse efeito, o maior valor de vencimento básico aplicável ao respectivo cargo."', 'Camara', '255137', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=222012', 'gilberto-kassab-camara-completo-autoria-principal-tipos-verificados-1999-2004-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_1999_2004_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"gilberto-kassab-camara-completo-lote-b-20260511","coverage_id":"gilberto-kassab-camara-completo-autoria-principal-tipos-verificados-1999-2004-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_1999_2004_cutoff_20260511","previous_coverage_id":"gilberto-kassab-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"gilberto-kassab-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":74778,"proposicao_id_api":"255137","data_apresentacao":"2004-05-25T20:03","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Gilberto Kassab","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/74778","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/255137","autores_endpoint":"https://dadosabertos.camara.leg.br/a