    ('helder-salomao', 'PLP', '183', 2023, 'Inclui um § 1°-E ao art. 16 da Lei Complementar n° 123, de 14 de dezembro de 2006, dispondo que, para a exclusão de ofício, por parte dos entes federativos, em razão de qualquer uma das hipóteses de exclusão do tratamento jurídico diferenciado previsto no Estatuto da Microempresa ou da Empresa de Pequeno Porte ou do Simples Nacional, o ato administrativo deverá prever a suspensão de seus efeitos por prazo não inferior a noventa dias, contados da data da notificação ao contribuinte, para que seja possibilitada a autorregularização e a manutenção do enquadramento previsto na Lei Complementar.', 'Camara', '2385380', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=2323396', 'helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"helder-salomao-camara-completo-lote-b-20260511","coverage_id":"helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511","previous_coverage_id":"helder-salomao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"helder-salomao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178873,"proposicao_id_api":"2385380","data_apresentacao":"2023-09-04T19:08","ordem_assinatura":1,"proponente":1,"total_autores":1,