    ('helder-salomao', 'SOR', '9', 2022, 'EMENDA DE ACRÉSCIMO-APROPRIAÇÃO. CDEICS 1 Fomento a Artesãos e MPE. Com a retomada da economia no pós pandemia é fundamental fomentar as inovações para as Micro e Pequenas Empresas, tendo em vista o ambiente de negócios atual é preciso criar oportunidades através de mais investimentos no setor, especialmente com novos produtos e tecnologias. VALOR: TOTAL: 250.000.000', 'Camara', '2336788', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=2213187', 'helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"helder-salomao-camara-completo-lote-b-20260511","coverage_id":"helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511","previous_coverage_id":"helder-salomao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"helder-salomao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178873,"proposicao_id_api":"2336788","data_apresentacao":"2022-11-07T18:36","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Helder Salomão","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/178873","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2336788","autores_endpoint