    ('helder-salomao', 'SOR', '10', 2022, 'EMENDA DE ACRÉSCIMO-APROPRIAÇÃO. CDEICS 2 Economia Solidária. O Brasil atravessa uma grave crise econômica com mais de 30 milhões de pessoas miseráveis e com um desemprego de quase 15% da população economicamente ativa, é preciso investir em inovações e em novos arranjos produtivos que inclua estas essoas em situação de extrema vulnerabilidade, por isso propomos ampliar o recurso da ação que na PLOA encaminhada é insuficiente para dar uma resposta às necessidades da população. VALOR: TOTAL: 200.000.000', 'Camara', '2336787', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=2213186', 'helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"helder-salomao-camara-completo-lote-b-20260511","coverage_id":"helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511","previous_coverage_id":"helder-salomao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"helder-salomao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178873,"proposicao_id_api":"2336787","data_apresentacao":"2022-11-07T18:36","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Helder Salomão","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.