    ('helder-salomao', 'REQ', '9', 2021, 'Solicita sejam convocados os Senhores Fernando Azevedo e Silva, Ministro de Estado da Defesa e o Senhor Edson Leal Pujol, General Comandante do Exército, a fim de prestarem esclarecimentos sobre as pressões e intimidações impostas aos Ministros do Supremo Tribunal Federal, em abril de 2018, através de publicações realizadas em redes sociais pelo General Eduardo Villas Boas, na véspera do julgamento, pela Corte Suprema, de um Habeas Corpus de interesse do Presidente Lula e que, agora, se sabe, através de declarações do General (Villas Boas) publicadas em livro biográfico sobre ele, terem sido (as intimidações) um ato institucional do Exército brasileiro, discutido e decidido pelo Alto Comando da Instituição, realidade que caracteriza uma verdadeira insurreição e tipifica a prática de crime contra a segurança nacional.', 'Camara', '2274257', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1976618', 'helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"helder-salomao-camara-completo-lote-b-20260511","coverage_id":"helder-salomao-camara-completo-autoria-principal-tipos-verificados-2015-2026-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2026_cutoff_20260511","previous_coverage_id":"helder-salomao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"helder-salomao-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos veri