    ('jhc', 'PL', '3392', 2020, 'Acrescenta o artigo 13-A à lei 10.233/2001 que "Dispõe sobre a reestruturação dos transportes aquaviário e terrestre, cria o Conselho Nacional de Integração de Políticas de Transporte, a Agência Nacional de Transportes Terrestres, a Agência Nacional de Transportes Aquaviários e o Departamento Nacional de Infra-Estrutura de Transportes" para obrigar que os atos realizados com base naquela lei obriguem os concessionários, permissionários e autorizados a aceitarem meios magnéticos - cartão de crédito - de pagamento, sem prejuízo de outras formas de pagamento.', 'Camara', '2255544', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1905157', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2255544","data_apresentacao":"2020-06-18T10:09","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"JHC","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/