    ('jhc', 'PL', '3234', 2020, 'Altera a lei nº 8.745/1993 que “Dispõe sobre a contratação por tempo determinado para atender à necessidade temporária de excepcional interesse público, nos termos do inciso IX do art. 37 da Constituição Federal” para impedir a rescisão de contratos feitos com base naquela lei durante a emergência de saúde pública de importância internacional decorrente do coronavírus responsável pelo surto de 2019 de que trata a lei 13.979/2020.', 'Camara', '2254943', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1902774', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2254943","data_apresentacao":"2020-06-10T09:53","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"JHC","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/178842","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2254943","autores_endpoint":"https://