    ('jhc', 'PLP', '154', 2020, 'Altera a lei complementar nº 101/2000 que “Estabelece normas de finanças públicas voltadas para a responsabilidade na gestão fiscal e dá outras providências” para acrescer o §4º ao art. 25 para assegurar que os instrumentos de repasses tenham seus prazos de vigência dilatados enquanto a emergência de que trata a lei 13.959/2020 como medida de enfrentamento da emergência de saúde pública de importância internacional decorrente do coronavírus responsável pelo surto de 2019, assegurada a execução dos seus objetos em exercícios distintos do que originalmente convencionado.', 'Camara', '2254548', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1900862', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2254548","data_apresentacao":"2020-06-04T13:56","ordem_assinatura":1,"proponente":1,"total_autores":2,"autor_nome":"JHC","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.l