    ('jhc', 'PL', '2082', 2020, 'Altera a lei 10.179 que dispõe sobre os títulos da dívida pública de responsabilidade do Tesouro Nacional, consolidando a legislação em vigor sobre a matéria, para criar o Título Verde e Amarelo com a finalidade de financiar as ações para enfrentamento da emergência de saúde pública de importância internacional decorrente do coronavírus responsável pelo surto de 2019 de que trata a lei 13.979/2020.', 'Camara', '2250337', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1884986', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2250337","data_apresentacao":"2020-04-22T15:29","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"JHC","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/178842","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2250337","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v