    ('jhc', 'PL', '1257', 2020, 'Acrescenta o artigo 6º-C à lei 10.820/2003 para suspender as parcelas dos empréstimos feitos com base naquela lei enquanto durar o estado de calamidade pública reconhecido pelo Decreto Legislativo nº 6, de 20 de março de 2020, e da emergência de saúde pública de importância internacional decorrente do coronavírus (covid-19), decretada pelo Ministro de Estado da Saúde, em 3 de fevereiro de 2020, nos termos do disposto na Lei nº 13.979, de 6 de fevereiro de 2020.', 'Camara', '2242373', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1871602', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2242373","data_apresentacao":"2020-03-30T16:21","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"JHC","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/178842","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/22423