    ('jhc', 'PL', '703', 2020, 'Acrescenta os parágrafos 1º e 2º artigo 10 da lei 7.783/ 1983 que "Dispõe sobre o exercício do direito de greve, define as atividades essenciais, regula o atendimento das necessidades inadiáveis da comunidade" para impossibilitar a suspensão de serviços essenciais por inadimplemento durante crises sanitárias nacionais e autoriza que o Executivo reduza por Decreto a alíquota de tributos incidentes sobre esses serviços enquanto perdurar a crise.', 'Camara', '2239476', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1867164', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2239476","data_apresentacao":"2020-03-18T12:11","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"JHC","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/178842","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2239476","autores_endpoi