    ('jhc', 'RIC', '758', 2019, 'Requer o envio de pedido de informações ao Sr. Ministro da Economia acerca do Fundo Amazônia pelo Banco Nacional de Desenvolvimento Econômico e Social - BNDES, volume de doações, doadores, projetos e respectivos patrocinadores, se o BNDES atua na gestão do Fundo em parceria com outras instituições bancárias, financeiras ou de outra natureza, e se doações ao Fundo foram transferidas a qualquer entidade, notadamente bancárias, sob quais fundamentos, propósitos e se há política de controle de metas em relação aos projetos e investimentos custeados com recursos do Fundo.', 'Camara', '2208813', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1767131', 'jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"jhc-camara-completo-lote-b-20260511","coverage_id":"jhc-camara-completo-autoria-principal-tipos-verificados-2015-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2015_2020_cutoff_20260511","previous_coverage_id":"jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"jhc-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","source_artifact":"fonte interna de curadoria","camara_id_deputado":178842,"proposicao_id_api":"2208813","data_apresentacao":"2019-06-19T14:35","ordem_assinatura":1,"proponente":1,"total_autores":1,"autor_nome":"Jhc","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg