    ('joao-campos', 'REQ', '50', 2019, 'Requer a realização de audiência pública para discutir a atual gestão das políticas públicas educacionais levadas a cabo pelo MEC sob perspectiva comparada com a presença de ex-titulares da pasta, com os seguintes convidados: 1. JOSÉ GOLDEMBERG, Ministro da Educação durante o governo Collor (1991-1992); 2. MURÍLIO HINGEL, Ministro da Educação durante o governo de Itamar Franco (1992-1995); 3. CRISTOVAM BUARQUE, Ministro da Educação durante o Governo Lula (2003-2005); 4. FERNANDO HADDAD, Ministro da Educação durante os governos Lula e Dilma (2005-2012); 5. ALOIZIO MERCADANTE, Ministro da Educação durante o Governo Dilma (2012-2014) e (2015-2016); e 6. RENATO JANINE RIBEIRO, Ministro da Educação durante o Governo Dilma (2015); 7. MENDONÇA FILHO, Ministro da Educação Durante o Governo Temer (2016-2018).', 'Camara', '2219205', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=1804198', 'joao-campos-camara-completo-autoria-principal-tipos-verificados-2019-2020-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2019_2020_cutoff_20260511', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"joao-campos-camara-completo-lote-b-20260511","coverage_id":"joao-campos-camara-completo-autoria-principal-tipos-verificados-2019-2020-cutoff-20260511","coverage_scope":"inventario_completo_camara_autoria_principal_tipos_verificados_2019_2020_cutoff_20260511","previous_coverage_id":"joao-campos-camara-autoria-principal-ampliado-parcial-lote-a-20260506","previous_coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","previous_coverage_like":"joao-campos-camara-autoria-principal-ampliado-parcial%","coverage_status":"completo_escopado","coverage_policy":"camara_autoria_principal_tipos_verificados_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos verificados","cutoff":"2026-05-11","so