DO $$
DECLARE
  expected record;
  cand_id uuid;
  seed_count int;
  blocked_conflict_count int;
  target_count int;
  metadata_count int;
  lme_count int;
  other_slug_count int;
BEGIN
  FOR expected IN SELECT * FROM _camara_lote_b_completo_expected LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = expected.slug;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: candidato ausente neste banco local/CI minimo; seed completo escopado pulado', expected.slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO seed_count
    FROM _camara_lote_b_completo_seed
    WHERE slug = expected.slug;

    IF seed_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pre-condicao %: seed tem % rows, esperado %', expected.slug, seed_count, expected.expected_rows;
    END IF;

    SELECT count(*) INTO lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    IF lme_count <> expected.expected_lme_rows THEN
      RAISE EXCEPTION 'Pre-condicao %: LME mudou de % para %', expected.slug, expected.expected_lme_rows, lme_count;
    END IF;

    SELECT count(*) INTO blocked_conflict_count
    FROM projetos_lei pl
    JOIN _camara_lote_b_completo_seed seed
      ON seed.slug = expected.slug
     AND seed.proposicao_id_api = pl.proposicao_id_api
    WHERE pl.candidato_id = cand_id
      AND pl.coverage_id IS NOT NULL
      AND pl.coverage_id <> seed.coverage_id
      AND pl.coverage_id IS DISTINCT FROM (seed.metadata->>'previous_coverage_id')
      AND pl.coverage_id NOT LIKE (seed.metadata->>'previous_coverage_like');

    IF blocked_conflict_count <> 0 THEN
      RAISE EXCEPTION 'Pre-condicao %: % rows aceitas tem coverage_id conflitante', expected.slug, blocked_conflict_count;
    END IF;
  END LOOP;

  INSERT INTO projetos_lei (
    candidato_id,
    tipo,
    numero,
    ano,
    ementa,
    fonte,
    proposicao_id_api,
    url_inteiro_teor,
    coverage_id,
    coverage_scope,
    metadata
  )
  SELECT
    c.id,
    seed.tipo,
    seed.numero,
    seed.ano,
    seed.ementa,
    seed.fonte,
    seed.proposicao_id_api,
    seed.url_inteiro_teor,
    seed.coverage_id,
    seed.coverage_scope,
    seed.metadata
  FROM _camara_lote_b_completo_seed seed
  JOIN candidatos c ON c.slug = seed.slug
  ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
    tipo = EXCLUDED.tipo,
    numero = EXCLUDED.numero,
    ano = EXCLUDED.ano,
    ementa = EXCLUDED.ementa,
    fonte = EXCLUDED.fonte,
    url_inteiro_teor = EXCLUDED.url_inteiro_teor,
    coverage_id = EXCLUDED.coverage_id,
    coverage_scope = EXCLUDED.coverage_scope,
    metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
  WHERE projetos_lei.coverage_id IS NULL
     OR projetos_lei.coverage_id = EXCLUDED.coverage_id
     OR projetos_lei.coverage_id IS NOT DISTINCT FROM (EXCLUDED.metadata->>'previous_coverage_id')
     OR projetos_lei.coverage_id LIKE (EXCLUDED.metadata->>'previous_coverage_like');

  FOR expected IN SELECT * FROM _camara_lote_b_completo_expected LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = expected.slug;

    IF cand_id IS NULL THEN
      CONTINUE;
    END IF;

    SELECT count(*) INTO target_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = expected.coverage_id
      AND coverage_scope = expected.coverage_scope;

    SELECT count(*) INTO metadata_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = expected.coverage_id
      AND coverage_scope = expected.coverage_scope
      AND metadata->>'coverage_status' = 'completo_escopado'
      AND metadata->>'tabela_alvo' = 'projetos_lei'
      AND metadata->>'legislacao_mandato_executivo_mixed' = 'false'
      AND metadata->>'autoria_principal_verificada' = 'true';

    SELECT count(*) INTO lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    SELECT count(*) INTO other_slug_count
    FROM projetos_lei
    WHERE candidato_id <> cand_id
      AND coverage_id = expected.coverage_id;

    IF target_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows completas, esperado %', expected.slug, target_count, expected.expected_rows;
    END IF;

    IF metadata_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows com metadata completa, esperado %', expected.slug, metadata_count, expected.expected_rows;
    END IF;

    IF lme_count <> expected.expected_lme_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: LME mudou de % para %', expected.slug, expected.expected_lme_rows, lme_count;
    END IF;

    IF other_slug_count <> 0 THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows de outros slugs com coverage_id alvo', expected.slug, other_slug_count;
    END IF;
  END LOOP;
END $$;
